import { useState, useEffect } from "react";
import MovieList from "./components/MovieList";
import MoviePopup from "./components/MoviePopup";
import { searchMovies } from "./services/movieService";
import { useWindowWidth } from "./hooks/useWindowWidth";
import "./App.css";

function App() {
  const width = useWindowWidth();
  const [movies, setMovies] = useState([]);
  const [loading, setLoading] = useState(false);
  const [searchTerm, setSearchTerm] = useState("");
  const [selectedMovie, setSelectedMovie] = useState(null);

  useEffect(() => {
    performSearch("avengers");
  }, []);

  const performSearch = async (term) => {
    if (!term.trim()) return;
    setLoading(true);
    const results = await searchMovies(term);
    setMovies(results);
    setLoading(false);
  };

  const handleDeleteMovie = (id) => {
    setMovies(prev => prev.filter(m => m.id !== id));
    setSelectedMovie(null); // Close popup if deleted
  };

  const handleUpdateMovie = (id, newTitle) => {
    setMovies(prev => prev.map(m => m.id === id ? { ...m, title: newTitle } : m));
  };

  return (
    <div className="app-container">
      <header className="hero">
        <nav className="navbar"><div className="logo">VELLUM</div></nav>
        <div className="hero-content">
          <h1>Unlimited movies, series and more</h1>
          <div className="search-box">
            <input
              type="text"
              placeholder="Search movie..."
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              onKeyDown={(e) => e.key === "Enter" && performSearch(searchTerm)}
            />
            <button onClick={() => performSearch(searchTerm)} className={width < 600 ? "btn-mobile" : "btn-desktop"}>
              {width < 600 ? "🔍" : "Search Movie"}
            </button>
          </div>
        </div>
      </header>

      <main className="content">
        <h2>{searchTerm ? `Results for "${searchTerm}"` : "Trending Movies"}</h2>
        {loading ? <div className="loader">Loading...</div> :
          movies.length > 0 ? (
            <MovieList movies={movies} onSelect={setSelectedMovie} />
          ) : <p>No movies found. 🎬</p>
        }
      </main>

      {selectedMovie && (
        <MoviePopup
          movie={selectedMovie}
          onClose={() => setSelectedMovie(null)}
          onDelete={handleDeleteMovie}
          onUpdate={handleUpdateMovie}
        />
      )}
    </div>
  );
}

export default App;
